from flask import Flask, send_file, abort, request, jsonify
from flask_login import login_required, current_user
import os

app = Flask(__name__)

# Configure your secret key and other settings
app.secret_key = 'your_secret_key'
app.config['UPLOAD_FOLDER'] = '/path/to/your/upload/folder'

@app.route('/download/<filename>', methods=['GET'])
@login_required
def download_file(filename):
    # Validate the filename to prevent directory traversal attacks
    if '..' in filename or filename.startswith('/'):
        abort(400, description="Invalid file name")

    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)

    # Check if the file exists and the user has permission to access it
    if not os.path.isfile(file_path):
        abort(404, description="File not found")

    # Serve the file securely
    return send_file(file_path, as_attachment=True)

@app.route('/files', methods=['GET'])
@login_required
def list_files():
    # List files in the upload folder
    files = os.listdir(app.config['UPLOAD_FOLDER'])
    return jsonify(files)

if __name__ == '__main__':
    app.run(ssl_context='adhoc')  # Use SSL/TLS for secure communication

from flask import Flask, request, render_template, redirect, url_for, flash
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime
import re

app = Flask(__name__)
app.secret_key = 'your_secret_key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///statuses.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db = SQLAlchemy(app)

class Status(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    content = db.Column(db.String(280), nullable=False)
    timestamp = db.Column(db.DateTime, default=datetime.utcnow)

    def __repr__(self):
        return f'<Status {self.id}>'

@app.route('/')
def index():
    statuses = Status.query.all()
    return render_template('index.html', statuses=statuses)

@app.route('/post', methods=['GET', 'POST'])
def post():
    if request.method == 'POST':
        content = request.form['content']
        if not content:
            flash('Status content cannot be empty.')
            return redirect(url_for('post'))

        if len(content) > 280:
            flash('Status content must be 280 characters or less.')
            return redirect(url_for('post'))

        if not re.match(r'^[a-zA-Z0-9\s\.\,\!\?\(\)\-]+$', content):
            flash('Status content contains invalid characters.')
            return redirect(url_for('post'))

        new_status = Status(content=content)
        db.session.add(new_status)
        db.session.commit()
        flash('Status posted successfully!')
        return redirect(url_for('index'))

    return render_template('post.html')

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)

