```python
import subprocess
import shlex

def execute_docker_command(image_name):
    try:
        # Validate the image name to prevent injection attacks
        if not shlex.isidentifier(image_name):
            raise ValueError("Invalid image name. Please provide a valid Docker image name.")

        # Execute the Docker command
        result = subprocess.run(['docker', 'run', image_name], capture_output=True, text=True, check=True)
        print(result.stdout)
    except subprocess.CalledProcessError as e:
