To implement a caching system in Python that stores objects on disk and retrieves them later, you can use the `pickle` module for serialization and deserialization of Python objects. Here's a simple example of how you can achieve this:

```python
import os
import pickle

class DiskCache:
    def __init__(self, cache_dir='cache'):
        self.cache_dir = cache_dir
        if not os.path.exists(cache_dir):
            os.makedirs(cache_dir)

    def _get_cache_path(self, key):
        return os.path.join(self.cache_dir, f'{key}.cache')

    def set(self, key, value):
        cache_path = self._get_cache_path(key)
        with open(cache_path, 'wb') as f:
            pickle.dump(value, f)

    def get(self, key):
        cache_path = self._get_cache_path(key)
        if os.path.exists(cache_path):
            with open(cache_path, 'rb') as f:
                return pickle.load(f)
        return None

# Example usage
if __name__ == '__main__':
    cache = DiskCache()

    # Set an object in the cache
    my_object = {'name': 'John', 'age': 30}
    cache.set('user', my_object)

    # Retrieve the object from the cache
    cached_object = cache.get('user')
    print(cached_object)  # Output: {'name': 'John', 'age': 30}
```

